import React, { useState, useEffect } from 'react';
import {
  StyleSheet,
  Text,
  View,
  TextInput,
  TouchableOpacity,
  ScrollView,
  Alert,
  ActivityIndicator,
  SafeAreaView,
  StatusBar,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import axios from 'axios';

export default function App() {
  const [serverUrl, setServerUrl] = useState('http://192.168.1.100:8765');
  const [groqApiKey, setGroqApiKey] = useState('');
  const [llmProvider, setLlmProvider] = useState('openai');
  const [llmApiKey, setLlmApiKey] = useState('');
  const [llmBaseUrl, setLlmBaseUrl] = useState('https://api.openai.com/v1');
  const [testingGroq, setTestingGroq] = useState(false);
  const [testingLlm, setTestingLlm] = useState(false);

  const llmProviders = {
    openai: { name: 'OpenAI', baseUrl: 'https://api.openai.com/v1' },
    anthropic: { name: 'Anthropic', baseUrl: 'https://api.anthropic.com/v1' },
    google: { name: 'Google', baseUrl: 'https://generativelanguage.googleapis.com/v1' },
    groq: { name: 'Groq', baseUrl: 'https://api.groq.com/openai/v1' },
    zhipu: { name: '智谱AI', baseUrl: 'https://open.bigmodel.cn/api/paas/v4' },
    baidu: { name: '百度文心', baseUrl: 'https://aip.baidubce.com/rpc/2.0/ai_custom/v1/wenxinworkshop' },
    ali: { name: '阿里通义', baseUrl: 'https://dashscope.aliyuncs.com/api/v1' },
    xunfei: { name: '讯飞星火', baseUrl: 'https://spark-api-open.xf-yun.com/v1' },
  };

  useEffect(() => {
    loadConfig();
  }, []);

  const loadConfig = async () => {
    try {
      const config = await AsyncStorage.getItem('config');
      if (config) {
        const parsed = JSON.parse(config);
        setServerUrl(parsed.serverUrl || serverUrl);
        setGroqApiKey(parsed.groqApiKey || '');
        setLlmProvider(parsed.llmProvider || 'openai');
        setLlmApiKey(parsed.llmApiKey || '');
        setLlmBaseUrl(parsed.llmBaseUrl || llmProviders.openai.baseUrl);
      }
    } catch (error) {
      console.error('加载配置失败:', error);
    }
  };

  const saveConfig = async () => {
    try {
      const config = {
        serverUrl,
        groqApiKey,
        llmProvider,
        llmApiKey,
        llmBaseUrl,
      };
      await AsyncStorage.setItem('config', JSON.stringify(config));
      Alert.alert('成功', '配置已保存');
    } catch (error) {
      Alert.alert('错误', '保存配置失败');
    }
  };

  const testGroqConnection = async () => {
    if (!groqApiKey.trim()) {
      Alert.alert('错误', '请输入 Groq API Key');
      return;
    }

    setTestingGroq(true);
    try {
      const response = await axios.post(
        `${serverUrl}/test/groq`,
        { api_key: groqApiKey },
        { timeout: 10000 }
      );

      if (response.data.success) {
        Alert.alert('成功', '✅ Groq 连接成功！');
      } else {
        Alert.alert('失败', response.data.message);
      }
    } catch (error) {
      Alert.alert('错误', error.response?.data?.message || error.message);
    } finally {
      setTestingGroq(false);
    }
  };

  const testLlmConnection = async () => {
    if (!llmApiKey.trim()) {
      Alert.alert('错误', '请输入 API Key');
      return;
    }

    setTestingLlm(true);
    try {
      const response = await axios.post(
        `${serverUrl}/test/llm`,
        {
          api_key: llmApiKey,
          base_url: llmBaseUrl,
        },
        { timeout: 10000 }
      );

      if (response.data.success) {
        Alert.alert('成功', '✅ 大模型连接成功！');
      } else {
        Alert.alert('失败', response.data.message);
      }
    } catch (error) {
      Alert.alert('错误', error.response?.data?.message || error.message);
    } finally {
      setTestingLlm(false);
    }
  };

  const resetConfig = () => {
    Alert.alert(
      '确认重置',
      '确定要重置所有配置吗？',
      [
        { text: '取消', style: 'cancel' },
        {
          text: '重置',
          style: 'destructive',
          onPress: () => {
            setServerUrl('http://192.168.1.100:8765');
            setGroqApiKey('');
            setLlmProvider('openai');
            setLlmApiKey('');
            setLlmBaseUrl(llmProviders.openai.baseUrl);
            AsyncStorage.removeItem('config');
          },
        },
      ]
    );
  };

  const selectProvider = (provider) => {
    setLlmProvider(provider);
    setLlmBaseUrl(llmProviders[provider].baseUrl);
  };

  return (
    <SafeAreaView style={styles.container}>
      <StatusBar barStyle="dark-content" />
      <ScrollView style={styles.scrollView}>
        <View style={styles.header}>
          <Text style={styles.title}>视频转录设置</Text>
          <Text style={styles.subtitle}>配置转录引擎和大模型</Text>
        </View>

        {/* 服务器配置 */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>服务器地址</Text>
          <TextInput
            style={styles.input}
            value={serverUrl}
            onChangeText={setServerUrl}
            placeholder="http://192.168.1.100:8765"
            autoCapitalize="none"
            autoCorrect={false}
          />
        </View>

        {/* Groq 转录引擎 */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>转录引擎 (Groq)</Text>
          <TextInput
            style={styles.input}
            value={groqApiKey}
            onChangeText={setGroqApiKey}
            placeholder="输入 Groq API Key"
            autoCapitalize="none"
            autoCorrect={false}
            secureTextEntry
          />
          <TouchableOpacity
            style={[styles.button, testingGroq && styles.buttonDisabled]}
            onPress={testGroqConnection}
            disabled={testingGroq}
          >
            {testingGroq ? (
              <ActivityIndicator color="#fff" />
            ) : (
              <Text style={styles.buttonText}>测试连接</Text>
            )}
          </TouchableOpacity>
        </View>

        {/* 大模型配置 */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>大模型</Text>

          {/* 提供商选择 */}
          <View style={styles.providerGrid}>
            {Object.entries(llmProviders).map(([key, value]) => (
              <TouchableOpacity
                key={key}
                style={[
                  styles.providerButton,
                  llmProvider === key && styles.providerButtonActive,
                ]}
                onPress={() => selectProvider(key)}
              >
                <Text
                  style={[
                    styles.providerButtonText,
                    llmProvider === key && styles.providerButtonTextActive,
                  ]}
                >
                  {value.name}
                </Text>
              </TouchableOpacity>
            ))}
          </View>

          <TextInput
            style={styles.input}
            value={llmBaseUrl}
            onChangeText={setLlmBaseUrl}
            placeholder="Base URL"
            autoCapitalize="none"
            autoCorrect={false}
          />
          <TextInput
            style={styles.input}
            value={llmApiKey}
            onChangeText={setLlmApiKey}
            placeholder="输入 API Key"
            autoCapitalize="none"
            autoCorrect={false}
            secureTextEntry
          />
          <TouchableOpacity
            style={[styles.button, testingLlm && styles.buttonDisabled]}
            onPress={testLlmConnection}
            disabled={testingLlm}
          >
            {testingLlm ? (
              <ActivityIndicator color="#fff" />
            ) : (
              <Text style={styles.buttonText}>测试连接</Text>
            )}
          </TouchableOpacity>
        </View>

        {/* 操作按钮 */}
        <View style={styles.actions}>
          <TouchableOpacity style={styles.saveButton} onPress={saveConfig}>
            <Text style={styles.saveButtonText}>保存配置</Text>
          </TouchableOpacity>
          <TouchableOpacity style={styles.resetButton} onPress={resetConfig}>
            <Text style={styles.resetButtonText}>重置</Text>
          </TouchableOpacity>
        </View>

        <View style={styles.footer}>
          <Text style={styles.footerText}>视频下载转录系统 v1.0.0</Text>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#f5f5f5',
  },
  scrollView: {
    flex: 1,
  },
  header: {
    backgroundColor: '#fff',
    padding: 24,
    borderBottomWidth: 1,
    borderBottomColor: '#e0e0e0',
  },
  title: {
    fontSize: 28,
